import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Grid } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface WidgetData {
  variables: string[];
  correlations: number[][];
}

export default function Widget() {
  const data = response.data as WidgetData;
  const variables = data.variables;
  const correlations = data.correlations;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1A202C' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Typography variant="h6" sx={{ mb: 1, color: '#9F7AEA' }}>
          Correlation Matrix
        </Typography>
        <Box sx={{ width: '100%', height: 250 }}>
          <ResponsiveChartContainer
            series={[
              {
                type: 'bar',
                data: correlations.flatMap((row) => row),
                color: '#4A5568',
              },
            ]}
            xAxis={[
              {
                scaleType: 'band',
                data: variables.flatMap((v) => variables.map(() => v)),
                id: 'variables',
              },
            ]}
            yAxis={[{ id: 'correlation' }]}
          >
            <g clipPath={`url(#${clipPathId})`}>
              <BarPlot />
            </g>
            <ChartsXAxis
              axisId="variables"
              tickLabelStyle={{ fontSize: 10, fill: '#A0AEC0' }}
            />
            <ChartsYAxis
              axisId="correlation"
              tickLabelStyle={{ fontSize: 10, fill: '#A0AEC0' }}
            />
            <ChartsClipPath id={clipPathId} />
          </ResponsiveChartContainer>
        </Box>

        <Grid container spacing={1} sx={{ mt: 1 }}>
          {variables.map((variable, index) => (
            <Grid item xs={6} key={index}>
              <Typography variant="body2" sx={{ color: '#E2E8F0', textAlign: 'center' }}>
                {variable}
              </Typography>
            </Grid>
          ))}
        </Grid>
      </CardContent>
    </Card>
  );
}
